<template>
  <div class="auth-module">
    <h4>Войти</h4>
    <input type="text" placeholder="E-mail" v-model="email" />
    <input type="password" placeholder="Пароль" v-model="password" />
    <p class="error-message" v-if="errMsg">{{ errMsg }}</p>
    <button @click="register">Войти</button>
    <button @click="SignInWithGoogle">Войти через Google</button>
  </div>
</template>

<script setup>
import { ref } from "vue";
import {
  getAuth,
  GoogleAuthProvider,
  signInWithEmailAndPassword,
  signInWithPopup,
} from "firebase/auth";
import router from "@/router";
const email = ref("");
const password = ref("");
const errMsg = ref("");

const register = () => {
  signInWithEmailAndPassword(getAuth(), email.value, password.value)
    .then((data) => {
      console.log("Registered", data);
      router.push("/home");
    })
    .catch((error) => {
      console.log(error.code);
      switch (error.code) {
        case "auth/invalid-email":
          errMsg.value = "Неправильный пароль";
          break;
        case "auth/user-not-found":
          errMsg.value = "По данным логину и паролю ничего не найдено!";
          break;
        default:
          errMsg.value = "Проверьте логин или пароль!";
      }
    });
};
const SignInWithGoogle = () => {
  const provider = new GoogleAuthProvider();
  signInWithPopup(getAuth(), provider)
    .then((result) => {
      console.log(result.user);
      router.push("/home");
    })
    .catch((error) => {
      console.log(error);
    });
};
</script>
